@CommandHandler(SendEmailCommand)
export class SendEmailHandler implements ICommandHandler<
  SendEmailCommand,
  void
> {
  constructor(
    private readonly notificationFactory: NotificationFactory,
    private readonly notificationRepository: NotificationRepository,
    private readonly emailAdaptor: EmailAdaptor,
  ) {}

  @Transactional()
  async execute(command: SendEmailCommand): Promise<void> {
    const notification = this.notificationFactory.create({
      ...command,
      id: this.notificationRepository.newId(),
    });
    await this.notificationRepository.save(notification);
    await this.emailAdaptor.sendEmail(
      command.to,
      command.subject,
      command.content,
    );
  }
}

@CommandHandler(Login)
export class LoginHandler implements ICommandHandler<Login> {
  constructor(
    @Inject('IAuthRepository') private readonly authRepository: IAuthRepository,
    @Inject('IUserRepository') private readonly userRepository: IUserRepository,
    private readonly commandBus: CommandBus
  ) {}

  async execute(command: Login): Promise<AuthDto> {
    await loginValidations.validateAsync(command);

    const user = await this.userRepository.findUserByEmail(command.email);

    if (!user || !(await isPasswordMatch(command.password, user.password as string))) {
      throw new ApplicationException('Incorrect email or password');
    }

    const token = await this.commandBus.execute(new GenerateToken({ userId: user.id }));

    return token;
  }
}

export class MiddlewareResolver {
  constructor(
    private readonly middlewareContainer: MiddlewareContainer,
    private readonly injector: Injector,
  ) {}

  public async resolveInstances(moduleRef: Module, moduleName: string) {
    const middlewareMap =
      this.middlewareContainer.getMiddlewareCollection(moduleName);
    const resolveInstance = async (wrapper: InstanceWrapper) =>
      this.resolveMiddlewareInstance(wrapper, middlewareMap, moduleRef);
    await Promise.all([...middlewareMap.values()].map(resolveInstance));
  }

  private async resolveMiddlewareInstance(
    wrapper: InstanceWrapper,
    middlewareMap: Map<InjectionToken, InstanceWrapper>,
    moduleRef: Module,
  ) {
    await this.injector.loadMiddleware(wrapper, middlewareMap, moduleRef);
  }
}

@Injectable()
export class ReminderOrchestrationService {
  constructor(private readonly reminderRepo: ReminderRepo, private readonly reminderArchiveRepo: ReminderArchiveRepo) {}

  public async sendReminderToArchive(
    cmd: SendReminderToArchiveCommand,
    accessPermissions?: AccessPermissionsContract,
  ): Promise<void> {
    // get reminder
    const reminder = await this.reminderRepo.findById(cmd.reminderId, { accessPermissions });

    // remove from Reminder data store
    this.reminderRepo.delete(cmd.reminderId, { accessPermissions });

    // add to ReminderArchive data store
    this.reminderArchiveRepo.create(
      {
        title: reminder.title,
        deadline: reminder.deadline,
        complete: reminder.complete,
        userId: reminder.userId,
        orgId: reminder.orgId,
        archivedDate: new Date(),
      },
      { accessPermissions },
    );
  }
}

@QueryHandler(Query)
export class Service implements IQueryHandler<Query, QueryOutput> {
  private readonly logger = new Logger('GetRealUrl.Service');

  constructor(
    private readonly idObfuscatorService: IdObfuscatorService,
    private readonly numberHasherService: NumberHasherService,
    private readonly urlRepository: UrlRepository,
  ) {}

  async execute(cmd: Query): Promise<QueryOutput> {
    this.logger.debug({
      msg: 'Retrieving real URL for shortUrlId',
      shortUrlId: cmd.shortUrlId,
    });

    const id = this.numberHasherService.decode(cmd.shortUrlId);
    const obfuscatedId = this.idObfuscatorService.deobfuscate(id);

    this.logger.debug({ msg: 'Deobfuscated ID', obfuscatedId: obfuscatedId });
    const url = await this.urlRepository.getUrlById(obfuscatedId);

    return new QueryOutput({
      url: url,
    });
  }
}

@ValidatorConstraint({ name: 'IsLegalNameExpression', async: false })
export class IsLegalNameExpression implements ValidatorConstraintInterface {
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  validate(value: string, args: ValidationArguments) {
    try {
      if (isEmpty(value)) {
        throw new Error('dir name is empty');
      }
      if (value.includes('/')) {
        throw new Error('dir name not allow /');
      }
      return true;
    } catch (e) {
      return false;
    }
  }

  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  defaultMessage(_args: ValidationArguments) {
    // here you can provide default error message if validation failed
    return 'file or dir name invalid';
  }
}

