@Injectable()
export class BootstrapService {
  constructor(
    private readonly middlewareSetup: services.MiddlewareSetupService,
    private readonly globalSetup: services.GlobalSetupService,
    private readonly readiness: services.ReadinessService,
    private readonly server: services.ServerService,
    private readonly shutdown: services.ShutdownService,
  ) {}

  init(app: INestApplication): void {
    const moduleRef = app.get(ModuleRef);
    this.globalSetup.setup(app, moduleRef);
    this.middlewareSetup.setup(app);
    app.enableShutdownHooks();
    this.shutdown.registerHandlers(app);
  }

  async start(app: INestApplication): Promise<void> {
    await this.readiness.run();
    await this.server.start(app);
  }
}

@Injectable()
export class ChangePasswordService {
  constructor(
    private readonly repository: ChangePasswordRepository,
    private readonly configService: ConfigService,
  ) {}

  public async createChangePasswordRequest(
    user: User,
  ): Promise<ChangePassword> {
    const changePassword: ChangePassword = new ChangePassword();
    changePassword.user = user;
    changePassword.expirationTime = this.configService.changePasswordExpirationTime;
    return this.repository.save(changePassword);
  }

  public async findById(id: string): Promise<ChangePassword> {
    const changePassword: ChangePassword = await this.repository.findOne(
      { id },
      { relations: ['user'] },
    );
    if (!changePassword) {
      throw new NotFoundException();
    }
    return changePassword;
  }
}

export class DataLoaderFactory {
  private static initializeContext(context: NestjsQueryExecutionContext): Record<string, Dataloader<unknown, unknown>> {
    if (!context.nestjsQueryLoaders) {
      // eslint-disable-next-line no-param-reassign
      context.nestjsQueryLoaders = {};
    }
    return context.nestjsQueryLoaders;
  }

  static getOrCreateLoader<K, V>(
    context: NestjsQueryExecutionContext,
    name: string,
    handler: Dataloader.BatchLoadFn<K, V>,
  ): Dataloader<K, V> {
    const nestjsQueryLoaders = this.initializeContext(context);
    if (!nestjsQueryLoaders[name]) {
      // eslint-disable-next-line no-param-reassign
      nestjsQueryLoaders[name] = new Dataloader(handler, { cacheKeyFn });
    }
    return nestjsQueryLoaders[name] as Dataloader<K, V>;
  }
}

