try {
  // Verify the token. If an identity is declared, it MUST be valid (Explicit Failure policy)
  const payload = await authAccessTokenService.verifyToken(token)
  if (!payload) throw new UnauthorizedException('Access denied: invalid identity payload')
  // Map AuthRole to IdentityRole based on token payload
  if (payload.role === AuthRole.Admin) {
    request.identity = new Identity({ role: IdentityRole.Admin, token, payload })
  } else if (payload.role === AuthRole.User) {
    request.identity = new Identity({ role: IdentityRole.User, token, payload })
  }
} catch (error) {
  // Fail explicitly if the token is invalid (expired, forged, or tampered)
  // This prevents confusion and enhances security for authenticated users
  throw error instanceof UnauthorizedException
    ? error
    : new UnauthorizedException('Authentication failed: token expired or malformed', { cause: error })
}

export class AccessPermissionsEntityAuthCheck extends AuthCheckContract<AccessPermissionsEntity, CrudOperations> {
  private orgAdminAuthCheck = new OrgRolesAuthCheck([OrganizationRoles.admin]);

  public async isAuthorized(params: AuthorizationCheckParams<AccessPermissionsEntity, CrudOperations>): Promise<boolean> {
    if (!params.targetResource || !params.targetResource) throw new AppError('target.resource can not be null');

    const scopedParams = {
      accessPermissions: params.accessPermissions,
      origin: params.origin,
      operation: params.operation,
      targetResource: new ScopedData(),
      data: params.data,
    };

    if (params.targetResource.organizations) {
      for (const orgAccess of params.targetResource.organizations) {
        scopedParams.targetResource.orgId = orgAccess.orgId;
        await this.orgAdminAuthCheck.ensureAuthorized(scopedParams);
      }
    }

    // if authorization not already denied, then allow access (return true)
    return true;
  }
}

export class ScopedAccessAuthCheck extends AuthCheckContract<ScopedData, any> {
  private orgAuthCheck = new OrgAccessAuthCheck();
  private userAuthCheck = new UserAccessAuthCheck();

  public async isAuthorized(params: AuthorizationCheckParams<any, any>): Promise<boolean> {
    // if entity has an orgId, and the accessPermissions don't allow access to this org, then deny authorization (return false)
    if (params.targetResource.orgId) {
      if (!(await this.orgAuthCheck.isAuthorized(params))) {
        return false;
      }
    }

    // if entity has a userId, and the accessPermissions don't allow access to this user, then deny authorization (return false)
    if (params.targetResource.userId) {
      if (!(await this.userAuthCheck.isAuthorized(params))) {
        return false;
      }
    }

    // if authorization not denied for either org or user access, then allow access (return true)
    return true;
  }
}

export class ScopedEntityAuthCheck extends AuthCheckContract<IEntity, CrudOperations> {
  private scopedAccessAuthCheck = new ScopedAccessAuthCheck();

  public async isAuthorized(params: AuthorizationCheckParams<IEntity, CrudOperations>): Promise<boolean> {
    if (!params.targetResource || !params.targetResource) throw new AppError('target.resource can not be null');

    const scopedParams = {
      accessPermissions: params.accessPermissions,
      origin: params.origin,
      operation: params.operation,
      targetResource: new ScopedData(),
      data: params.data,
    };

    scopedParams.targetResource.userId = params.targetResource['userId'];
    scopedParams.targetResource.orgId = params.targetResource['orgId'];

    return this.scopedAccessAuthCheck.isAuthorized(params);
  }
}

const taskList = fromPairs(
  handlers.map((h) => {
    const originalHandler = this.externalContextCreator.create(
      h.discoveredMethod.parentClass.instance,
      h.discoveredMethod.handler,
      h.discoveredMethod.methodName,
      undefined, // metadataKey
      undefined, // paramsFactory
      undefined, // contextId
      undefined, // inquirerId
      undefined, // options
      GRAPHILE_WORKER_CONTEXT_TYPE,
    );

    const taskHandlerName = h.meta.name as keyof GraphileWorkerTaskSchemas;
    const schema = this.options.tasksValidationSchemas[taskHandlerName];
    if (!schema) {
      throw new TaskHandlerValidationSchemaMissingError(h.meta.name);
    }

    return [
      taskHandlerName,
      createTaskGuard(taskHandlerName, schema, originalHandler),
    ];
  }),
);

if (options.validator instanceof Function) {
  constraintCls = options.validator;
  const constraintClasses = getFromContainer(MetadataStorage).getTargetValidatorConstraints(options.validator);
  if (constraintClasses.length > 1) {
    throw `More than one implementation of ValidatorConstraintInterface found for validator on: ${options.target.name}:${options.propertyName}`;
  }
} else {
  const validator = options.validator;
  constraintCls = class CustomConstraint implements ValidatorConstraintInterface {
    validate(value: any, validationArguments?: ValidationArguments): Promise<boolean> | boolean {
      return validator.validate(value, validationArguments);
    }

    defaultMessage(validationArguments?: ValidationArguments): string {
      if (validator.defaultMessage) {
        return validator.defaultMessage(validationArguments);
      }

      return '';
    }
  };
  getMetadataStorage().addConstraintMetadata(new ConstraintMetadata(constraintCls, options.name, options.async));
}

